export const lpic2_quiz_pool = [
  // Topic 200: Capacity Planning
  { id: 'lpic2-200-1', topicId: 1, question: 'Which command provides a real-time, dynamic view of the running system and processes, particularly emphasizing CPU and memory usage?', options: ['free', 'top', 'uptime', 'vmstat'], answer: 1, explanation: 'The `top` command provides a dynamic real-time view of a running system.' },
  { id: 'lpic2-200-2', topicId: 1, question: 'Which of the following commands would you use to view detailed I/O statistics for block devices?', options: ['vmstat', 'iostat', 'netstat', 'mpstat'], answer: 1, explanation: 'iostat command is used for monitoring system input/output device loading.' },
  { id: 'lpic2-200-3', topicId: 1, question: 'You want to collect and visualize system performance trends over several months. Which tool is best suited for this?', options: ['top', 'ss', 'Collectd/MRTG/Cacti', 'tcpdump'], answer: 2, explanation: 'Collectd, MRTG, and Cacti are standard monitoring tools designed to gather data over time and generate graphs for capacity planning.' },
  { id: 'lpic2-200-4', topicId: 1, question: 'Which tool can you use to predict future capacity needs based on current trends?', options: ['mrtg', 'ping', 'fsck', 'ls'], answer: 0, explanation: 'MRTG (Multi Router Traffic Grapher) is used to monitor traffic and capacity over time.' },
  { id: 'lpic2-200-5', topicId: 1, question: 'What does the `sar` command do?', options: ['Searches for files', 'System Activity Reporter', 'Saves archives', 'Stops all running processes'], answer: 1, explanation: 'sar (System Activity Reporter) is used to collect, report, or save system activity information.' },

  // Topic 201: Linux Kernel
  { id: 'lpic2-201-1', topicId: 2, question: 'Where do the default compiled kernel modules reside in the filesystem?', options: ['/boot/modules/', '/lib/modules/$(uname -r)/', '/etc/kernel/', '/var/lib/modules/'], answer: 1, explanation: 'Kernel modules are stored in `/lib/modules/` under a directory matching the specific kernel release version.' },
  { id: 'lpic2-201-2', topicId: 2, question: 'Which make target is used to build a compressed kernel image in modern 2.6+ kernels?', options: ['make zImage', 'make bzImage', 'make vmlinux', 'make install'], answer: 1, explanation: '`make bzImage` creates a compressed kernel image (big zImage) which handles kernels that exceed the old zImage size limitations.' },
  { id: 'lpic2-201-3', topicId: 2, question: 'When configuring the kernel via source, which command provides a text-based, menu-driven interface?', options: ['make config', 'make menuconfig', 'make xconfig', 'make defconfig'], answer: 1, explanation: '`make menuconfig` requires ncurses and provides a text-based menu interface for kernel configuration.' },
  { id: 'lpic2-201-4', topicId: 2, question: 'Which tool is used to load a kernel module along with its dependencies?', options: ['insmod', 'modinfo', 'modprobe', 'rmmod'], answer: 2, explanation: 'modprobe intelligently adds or removes a module from the Linux kernel, handling dependencies.' },
  { id: 'lpic2-201-5', topicId: 2, question: 'Which file contains the kernel symbols necessary for debugging?', options: ['vmlinux', 'System.map', 'bzImage', 'initrd'], answer: 1, explanation: 'System.map acts as a symbol table, mapping kernel symbol names to their memory addresses.' },

  // Topic 202: System Startup
  { id: 'lpic2-202-1', topicId: 3, question: 'In a traditional SysVinit system, which file dictates the default runlevel on boot?', options: ['/etc/inittab', '/etc/runlevel', '/boot/grub/grub.cfg', '/etc/init.d/rcS'], answer: 0, explanation: 'The `/etc/inittab` file configures the init process and sets the `initdefault` runlevel.' },
  { id: 'lpic2-202-2', topicId: 3, question: 'Which command updates the GRUB 2 configuration file on Debian-based systems?', options: ['grub-install', 'grub2-mkconfig', 'update-grub', 'grub-setup'], answer: 2, explanation: '`update-grub` is a script in Debian/Ubuntu that wraps around grub-mkconfig.' },
  { id: 'lpic2-202-3', topicId: 3, question: 'During a system recovery, you need to boot into single-user mode in systemd. Which target is used?', options: ['runlevel1.target', 'rescue.target', 'single.target', 'emergency.target'], answer: 1, explanation: '`rescue.target` is the systemd equivalent of single-user mode.' },
  { id: 'lpic2-202-4', topicId: 3, question: 'Where is the main configuration file for GRUB 2 typically located?', options: ['/boot/grub/grub.conf', '/boot/grub2/grub2.cfg', '/boot/grub/grub.cfg', '/etc/grub.cfg'], answer: 2, explanation: 'The primary generated configuration file for GRUB 2 is `/boot/grub/grub.cfg`.' },
  { id: 'lpic2-202-5', topicId: 3, question: 'Which parameter can you append to the kernel command line in GRUB to bypass the init system and open a root shell?', options: ['init=/bin/sh', 'single', 'rescue', 'bash'], answer: 0, explanation: 'Appending `init=/bin/sh` or `init=/bin/bash` mounts the root filesystem read-only and spawns a shell instead of starting systemd or SysVinit.' },

  // Topic 203: Filesystem and Devices
  { id: 'lpic2-203-1', topicId: 4, question: 'Which filesystem type relies heavily on extents and is the default for many modern RHEL-based distributions?', options: ['ext4', 'xfs', 'btrfs', 'zfs'], answer: 1, explanation: 'XFS is highly scalable and the default in RHEL 7+.' },
  { id: 'lpic2-203-2', topicId: 4, question: 'Which command checks an ext4 filesystem for errors?', options: ['fsck.ext4', 'e2fsck', 'Both A and B', 'xfs_repair'], answer: 2, explanation: '`fsck.ext4` is usually a hardlink or wrapper to `e2fsck`.' },
  { id: 'lpic2-203-3', topicId: 4, question: 'What is the purpose of the `/etc/fstab` file?', options: ['To configure the bootloader', 'To list filesystems that should be mounted automatically at boot', 'To store user passwords', 'To configure network interfaces'], answer: 1, explanation: 'fstab stands for file systems table and defines mounting rules.' },
  { id: 'lpic2-203-4', topicId: 4, question: 'Which smartctl option displays the overall health assessment of a hard drive?', options: ['-a', '-H', '-i', '-t short'], answer: 1, explanation: '`smartctl -H /dev/sda` shows the SMART health status (PASSED or FAILED).' },
  { id: 'lpic2-203-5', topicId: 4, question: 'How do you create an ISO image from a CD-ROM block device (/dev/cdrom)?', options: ['tar -cvf image.iso /dev/cdrom', 'dd if=/dev/cdrom of=image.iso', 'mkisofs -o image.iso /dev/cdrom', 'cp /dev/cdrom image.iso'], answer: 1, explanation: '`dd` is the standard tool for creating raw byte-for-byte copies of block devices, such as ripping an ISO.' },

  // Topic 204: Advanced Storage
  { id: 'lpic2-204-1', topicId: 5, question: 'Which tool is used to monitor, assemble, and manage software RAID arrays in Linux?', options: ['lvm', 'fdisk', 'mdadm', 'parted'], answer: 2, explanation: '`mdadm` stands for multiple device admin and is the standard utility for managing software RAID.' },
  { id: 'lpic2-204-2', topicId: 5, question: 'Which RAID level provides mirroring with no striping?', options: ['RAID 0', 'RAID 1', 'RAID 5', 'RAID 10'], answer: 1, explanation: 'RAID 1 provides redundancy by cloning data identically across two or more drives.' },
  { id: 'lpic2-204-3', topicId: 5, question: 'In LVM, which command is used to add a new physical hard drive to an existing Volume Group?', options: ['pvcreate', 'vgextend', 'lvextend', 'vgcreate'], answer: 1, explanation: '`vgextend groupname /dev/sdX` adds the initialized physical volume to the group.' },
  { id: 'lpic2-204-4', topicId: 5, question: 'Which hdparm flag is used to measure the read speed of a hard drive?', options: ['-T', '-S', '-t', '-y'], answer: 2, explanation: '`hdparm -t` performs timed device reads, while `-T` performs timed cache reads.' },
  { id: 'lpic2-204-5', topicId: 5, question: 'What is iSCSI primarily used for?', options: ['Internet browsing securely', 'Transmitting SCSI commands over IP networks', 'A replacement for NFS file sharing', 'Local hardware encryption'], answer: 1, explanation: 'iSCSI encapsulates SCSI control and data to enable block-level storage access over over IP networks (SANs).' },

  // Topic 205: Network Configuration
  { id: 'lpic2-205-1', topicId: 6, question: 'Which command allows you to view the ARP cache (neighbor table) using the modern iproute2 suite?', options: ['arp -n', 'ip neigh show', 'netstat -rn', 'route -n'], answer: 1, explanation: '`ip neigh show` (or simply `ip n`) replaces the old `arp` command.' },
  { id: 'lpic2-205-2', topicId: 6, question: 'Which command displays the current routing table using iproute2?', options: ['route', 'ip route show', 'netstat -r', 'ifconfig'], answer: 1, explanation: '`ip route show` or `ip r` is the proper iproute2 standard.' },
  { id: 'lpic2-205-3', topicId: 6, question: 'What does the `ping -c 4` command do?', options: ['Pings 4 different addresses', 'Sends exactly 4 ICMP echo request packets', 'Sets the packet size to 4 bytes', 'Waits 4 seconds between pings'], answer: 1, explanation: 'The `-c` flag stands for count, limiting ping to 4 packets.' },
  { id: 'lpic2-205-4', topicId: 6, question: 'Which tool is considered the standard network protocol analyzer (CLI packet sniffer) in Linux?', options: ['wireshark', 'nmap', 'tcpdump', 'tracepath'], answer: 2, explanation: 'tcpdump captures and analyzes network traffic directly on the command line.' },
  { id: 'lpic2-205-5', topicId: 6, question: 'What port does standard HTTPS operate on?', options: ['80', '21', '22', '443'], answer: 3, explanation: 'HTTPS (HTTP over TLS/SSL) uses port 443 by default.' },

  // Topic 206: System Maintenance
  { id: 'lpic2-206-1', topicId: 7, question: 'When compiling tarball source code natively, which order of commands is traditionally executed?', options: ['make > make install > ./configure', './configure > make > make install', 'make install > ./configure > make', 'untar > make install > ./configure'], answer: 1, explanation: 'You configure the build, compile it with make, and install the binaries with make install.' },
  { id: 'lpic2-206-2', topicId: 7, question: 'Which tool syncs files remotely and locally efficiently by sending only the differences (deltas)?', options: ['cp', 'scp', 'ftp', 'rsync'], answer: 3, explanation: 'rsync is renowned for its delta-transfer algorithm, reducing the amount of data sent over the network.' },
  { id: 'lpic2-206-3', topicId: 7, question: 'What does the `strace` command do?', options: ['Tracks system security vulnerabilities', 'Traces system calls and signals produced by a process', 'Optimizes disk storage', 'Monitors network strings'], answer: 1, explanation: 'strace intercepts and records the system calls which are called by a process.' },
  { id: 'lpic2-206-4', topicId: 7, question: 'Which command lists all open files and the processes that opened them?', options: ['lsof', 'ps', 'top', 'find'], answer: 0, explanation: '`lsof` stands for "list open files".' },
  { id: 'lpic2-206-5', topicId: 7, question: 'What is the standard tar flag for extracting a gzip-compressed archive?', options: ['-cvf', '-xvf', '-zxvf', '-jcvf'], answer: 2, explanation: '`-z` decompresses gzip, `-x` extracts, `-v` is verbose, and `-f` specifies the file.' },

  // Topic 207: Domain Name Server
  { id: 'lpic2-207-1', topicId: 8, question: 'In BIND, which DNS record type is used to map a hostname to an IPv4 address?', options: ['MX', 'CNAME', 'A', 'AAAA'], answer: 2, explanation: 'The A (Address) record maps a fully qualified domain name to an IPv4 address.' },
  { id: 'lpic2-207-2', topicId: 8, question: 'Which BIND command-line tool verifies the syntax of a zone file?', options: ['named-checkconf', 'named-checkzone', 'dns-lint', 'dig'], answer: 1, explanation: '`named-checkzone` checks the syntax and integrity of a zone file before reloading BIND.' },
  { id: 'lpic2-207-3', topicId: 8, question: 'What does an MX record do?', options: ['Maps IPs to hostnames', 'Provides Mail Exchange routing', 'Provides IPv6 addresses', 'Aliases one name to another'], answer: 1, explanation: 'MX records specify the mail servers responsible for accepting email messages on behalf of a domain.' },
  { id: 'lpic2-207-4', topicId: 8, question: 'Which technology prevents DNS spoofing by cryptographically signing zone data?', options: ['DNS-Over-HTTPS (DoH)', 'TLS', 'DNSSEC', 'TSIG'], answer: 2, explanation: 'DNSSEC (Domain Name System Security Extensions) provides origin authentication and data integrity.' },
  { id: 'lpic2-207-5', topicId: 8, question: 'Which file configures the primary behavior of the BIND `named` daemon?', options: ['/etc/bind/bind.conf', '/etc/named.conf', '/var/named/config', '/etc/resolv.conf'], answer: 1, explanation: 'The main configuration file is traditionally `/etc/named.conf` or `/etc/bind/named.conf` on Debian variants.' },

  // Topic 208: Web Services
  { id: 'lpic2-208-1', topicId: 9, question: 'In Apache HTTPD, which directive defines a separate website served from the same server based on the requested domain name?', options: ['<Directory>', '<ServerHost>', '<VirtualHost>', '<Website>'], answer: 2, explanation: '<VirtualHost> allows multiple domains (like site1.com and site2.com) to run on a single IP.' },
  { id: 'lpic2-208-2', topicId: 9, question: 'Nginx is heavily known for its ability to function as what?', options: ['A DNS server', 'A Reverse Proxy and Load Balancer', 'A purely internal file server', 'A kernel module'], answer: 1, explanation: 'Nginx excels at proxying web requests, load balancing, and serving static content efficiently.' },
  { id: 'lpic2-208-3', topicId: 9, question: 'Squid is primarily used as a...', options: ['SMTP Relay', 'Caching Web Proxy', 'Database Engine', 'Filesystem Manager'], answer: 1, explanation: 'Squid is a caching proxy for the Web supporting HTTP, HTTPS, FTP, and more.' },
  { id: 'lpic2-208-4', topicId: 9, question: 'Which Apache module is required to establish a secure SSL/TLS connection?', options: ['mod_rewrite', 'mod_security', 'mod_ssl', 'mod_proxy'], answer: 2, explanation: '`mod_ssl` provides strong cryptography for the Apache web server via SSL and TLS.' },
  { id: 'lpic2-208-5', topicId: 9, question: 'What port does a Squid proxy listen to by default?', options: ['80', '443', '3128', '8080'], answer: 2, explanation: 'Squid defaults to port 3128 for handling incoming proxy requests.' },

  // Topic 209: File Sharing
  { id: 'lpic2-209-1', topicId: 10, question: 'Which suite is required to share files from a Linux server to native Windows clients natively?', options: ['NFS', 'Samba', 'FTP', 'SSHFS'], answer: 1, explanation: 'Samba provides file and print services compatible with the SMB/CIFS protocol used by Windows.' },
  { id: 'lpic2-209-2', topicId: 10, question: 'Where is the main configuration file for Samba located?', options: ['/etc/smb/smb.conf', '/etc/samba/smb.conf', '/usr/local/samba.cfg', '/var/lib/samba/config'], answer: 1, explanation: '`/etc/samba/smb.conf` stores the workgroup, share definitions, and security policies.' },
  { id: 'lpic2-209-3', topicId: 10, question: 'Which file defines the directories to be shared by an NFS server?', options: ['/etc/exports', '/etc/nfs.conf', '/etc/fstab', '/etc/samba/smb.conf'], answer: 0, explanation: 'The `/etc/exports` file dictates which local directories are exported to which remote NFS clients.' },
  { id: 'lpic2-209-4', topicId: 10, question: 'What command forces the NFS server to re-read the /etc/exports file without restarting?', options: ['nfs-update', 'systemctl reload nfs', 'exportfs -a / -r', 'mount -a'], answer: 2, explanation: '`exportfs -arv` re-exports all directories by reading the modified /etc/exports file.' },
  { id: 'lpic2-209-5', topicId: 10, question: 'Which command adds a user to the Samba password database?', options: ['smbpasswd -a', 'useradd', 'passwd', 'pdbedit -n'], answer: 0, explanation: '`smbpasswd -a username` adds a Linux user to the Samba database.' },

  // Topic 210: Network Client Management
  { id: 'lpic2-210-1', topicId: 11, question: 'Which protocol dynamically assigns IP addresses to network clients?', options: ['DNS', 'DHCP', 'ARP', 'ICMP'], answer: 1, explanation: 'DHCP (Dynamic Host Configuration Protocol) leases IPs and network settings to clients.' },
  { id: 'lpic2-210-2', topicId: 11, question: 'What is the purpose of PAM (Pluggable Authentication Modules)?', options: ['It manages software packages', 'It dynamically authenticates users across various services seamlessly', 'It routes packets', 'It encrypts hard drives'], answer: 1, explanation: 'PAM allows system administrators to set authentication policies without recompiling programs.' },
  { id: 'lpic2-210-3', topicId: 11, question: 'What does LDAP stand for?', options: ['Linux Directory Authentication Protocol', 'Lightweight Directory Access Protocol', 'Local Domain Access Process', 'Large Data Authentication Platform'], answer: 1, explanation: 'LDAP is used for directory lookups and centralized authentication.' },
  { id: 'lpic2-210-4', topicId: 11, question: 'In OpenVPN, what is a TUN device?', options: ['A hardware router', 'A routed IP tunnel virtual interface', 'A bridged Ethernet virtual interface', 'An encryption key'], answer: 1, explanation: 'TUN operates at OSI Layer 3 (IP routing), whereas TAP operates at Layer 2 (Ethernet frames).' },
  { id: 'lpic2-210-5', topicId: 11, question: 'Which port does OpenVPN use by default?', options: ['1194 UDP', '22 TCP', '443 TCP', '53 UDP'], answer: 0, explanation: 'OpenVPN officially defaults to port 1194 on UDP.' },

  // Topic 211: E-Mail Services
  { id: 'lpic2-211-1', topicId: 12, question: 'Which protocol is used by Mail Transfer Agents (MTAs) like Postfix to send mail between servers?', options: ['POP3', 'IMAP', 'SMTP', 'SNMP'], answer: 2, explanation: 'SMTP (Simple Mail Transfer Protocol) is responsible for routing and sending emails.' },
  { id: 'lpic2-211-2', topicId: 12, question: 'What is the main configuration file for Postfix?', options: ['/etc/postfix/master.cf', '/etc/postfix/main.cf', '/etc/mail/sendmail.cf', '/var/spool/postfix/config'], answer: 1, explanation: '`main.cf` contains the global parameters for the Postfix MTA.' },
  { id: 'lpic2-211-3', topicId: 12, question: 'Which daemon is widely used for providing IMAP and POP3 access to mailboxes?', options: ['Postfix', 'Dovecot', 'Procmail', 'SpamAssassin'], answer: 1, explanation: 'Dovecot is a secure IMAP and POP3 server designed primarily for Linux systems.' },
  { id: 'lpic2-211-4', topicId: 12, question: 'What is the function of Procmail or Sieve?', options: ['Sending mail over the Internet', 'Filtering, sorting, and delivering incoming mail to local folders', 'Authenticating users via LDAP', 'Hosting DNS MX records'], answer: 1, explanation: 'They are Mail Delivery Agents (MDAs) used to apply rules (like moving spam) during final delivery to a mailbox.' },
  { id: 'lpic2-211-5', topicId: 12, question: 'What command in Postfix processes the /etc/aliases file after modification?', options: ['makemap', 'newaliases', 'postmap', 'systemctl reload postfix'], answer: 1, explanation: '`newaliases` reconstructs the alias database consumed by Postfix.' },

  // Topic 212: System Security
  { id: 'lpic2-212-1', topicId: 13, question: 'Which iptables table is used strictly for Network Address Translation (NAT) rules?', options: ['filter', 'mangle', 'nat', 'raw'], answer: 2, explanation: 'The `nat` table is consulted when a packet that creates a new connection is encountered, and is used to alter source/destination IPs.' },
  { id: 'lpic2-212-2', topicId: 13, question: 'What tool actively monitors log files for malicious activity (like SSH brute force) and automatically updates firewall rules to ban the IP?', options: ['Snort', 'Fail2ban', 'Nmap', 'OpenVAS'], answer: 1, explanation: 'Fail2ban scans logs and bans IPs that show the malicious signs -- effectively reducing brute-force success rates.' },
  { id: 'lpic2-212-3', topicId: 13, question: 'Which command is used to map open ports and discover services running on a remote host?', options: ['tcpdump', 'wireshark', 'nmap', 'ping'], answer: 2, explanation: 'Nmap (Network Mapper) is a security scanner used to discover hosts and services on a computer network.' },
  { id: 'lpic2-212-4', topicId: 13, question: 'What is OpenVAS?', options: ['A firewall interface', 'A vulnerability scanner framework', 'A VPN protocol', 'An open-source anti-virus'], answer: 1, explanation: 'OpenVAS (Open Vulnerability Assessment System) is a comprehensive vulnerability scanner.' },
  { id: 'lpic2-212-5', topicId: 13, question: 'Which iptables command sets the default action for the INPUT chain to DROP?', options: ['iptables -A INPUT -j DROP', 'iptables -P INPUT DROP', 'iptables -I INPUT DROP', 'iptables -D INPUT DROP'], answer: 1, explanation: '`-P` sets the Policy for the given chain. Setting it to DROP blocks all incoming traffic not explicitly allowed.' },
  // --- NEW BATCH 1 (Topics 200-204) ---
  { id: 'lpic2-200-6', topicId: 1, question: 'In the output of `vmstat`, what does the `wa` column indicate?', options: ['Waiting for CPU', 'Waiting for I/O', 'Waiting for network', 'Waiting for memory allocation'], answer: 1, explanation: 'The `wa` column in `vmstat` shows the percentage of CPU time spent waiting for I/O operations to complete.' },
  { id: 'lpic2-200-7', topicId: 1, question: 'Which command provides a quick summary of the system load averages for the past 1, 5, and 15 minutes?', options: ['w', 'uptime', 'Both A and B', 'sar'], answer: 2, explanation: 'Both `w` and `uptime` commands display the system load averages.' },
  { id: 'lpic2-200-8', topicId: 1, question: 'What is the primary protocol utilized by MRTG to collect data from network devices?', options: ['SSH', 'SMTP', 'SNMP', 'HTTP'], answer: 2, explanation: 'MRTG (Multi Router Traffic Grapher) predominantly relies on SNMP (Simple Network Management Protocol) to gather metrics.' },
  { id: 'lpic2-200-9', topicId: 1, question: 'Which command shows network interface statistics including dropped packets and overruns?', options: ['netstat -i', 'netstat -r', 'netstat -tulnp', 'ifconfig -a'], answer: 0, explanation: '`netstat -i` displays a table of all network interfaces and their respective transmit/receive statistics.' },
  { id: 'lpic2-200-10', topicId: 1, question: 'Which memory value in the `free` command output is most indicative of the memory available for starting new applications without swapping?', options: ['total', 'used', 'shared', 'available'], answer: 3, explanation: 'The `available` column estimates how much memory is available for starting new applications, without physical swapping.' },
  { id: 'lpic2-200-11', topicId: 1, question: 'How do you configure Collectd to store metrics efficiently over time?', options: ['Write to CSV', 'Write to RRDtool', 'Write to MySQL only', 'Write to syslog'], answer: 1, explanation: 'Collectd often uses the RRDtool (Round Robin Database) plugin to store time-series data efficiently.' },
  { id: 'lpic2-200-12', topicId: 1, question: 'Which tool is specifically built to show real-time per-process I/O usage similar to `top`?', options: ['iotop', 'iostat', 'ioping', 'blktrace'], answer: 0, explanation: '`iotop` displays a top-like UI showing per-process I/O read and write bandwidth.' },
  { id: 'lpic2-200-13', topicId: 1, question: 'What does a high `si` and `so` value in `vmstat` strongly suggest?', options: ['Network congestion', 'CPU bottleneck', 'Memory shortage and intense swapping', 'Disk hardware failure'], answer: 2, explanation: 'High Swap In (`si`) and Swap Out (`so`) rates indicate the system is actively thrashing memory to disk due to RAM exhaustion.' },
  { id: 'lpic2-200-14', topicId: 1, question: 'Which command lists all listening TCP and UDP sockets along with the PID of the process?', options: ['ss -tulnp', 'netstat -rn', 'ip route', 'arp -a'], answer: 0, explanation: '`ss -tulnp` (or netstat -tulnp) lists TCP/UDP listening ports and the associated Process IDs.' },
  { id: 'lpic2-200-15', topicId: 1, question: 'In capacity planning, what is a "baseline"?', options: ['The maximum capacity of the server', 'The minimum RAM required to boot', 'Historical data representing normal system behavior', 'The physical limit of the network card'], answer: 2, explanation: 'A baseline is a known, normal state of the system recorded over time to compare against anomalies or future growth.' },

  { id: 'lpic2-201-6', topicId: 2, question: 'Which command cleans the kernel source tree completely, removing all compiled files and the .config file?', options: ['make clean', 'make mrproper', 'make distclean', 'make wipe'], answer: 1, explanation: '`make mrproper` removes all generated files, including `.config` and various backup files, ensuring a pristine source tree.' },
  { id: 'lpic2-201-7', topicId: 2, question: 'What is the purpose of the `depmod` command?', options: ['To remove a module', 'To generate the modules.dep file for modprobe', 'To view module details', 'To compile modules'], answer: 1, explanation: '`depmod` surveys the kernel modules and generates a dependency list (`modules.dep`) that `modprobe` uses.' },
  { id: 'lpic2-201-8', topicId: 2, question: 'Which tool dynamically rebuilds kernel modules for third-party drivers (like Nvidia) upon a new kernel installation?', options: ['depmod', 'dracut', 'DKMS', 'kmod'], answer: 2, explanation: 'DKMS (Dynamic Kernel Module Support) is a framework that re-compiles external kernel modules whenever a new kernel is installed.' },
  { id: 'lpic2-201-9', topicId: 2, question: 'How can you view the currently active configuration of the running kernel (if supported by the kernel)?', options: ['cat /proc/kcore', 'zcat /proc/config.gz', 'cat /sys/kernel/config', 'dmesg | grep config'], answer: 1, explanation: 'If the `IKCONFIG_PROC` option is enabled, the running kernel configuration is exposed at `/proc/config.gz`.' },
  { id: 'lpic2-201-10', topicId: 2, question: 'Which command lists all currently loaded kernel modules?', options: ['lsmod', 'modinfo', 'modprobe -l', 'infomod'], answer: 0, explanation: '`lsmod` formats the contents of `/proc/modules` to show which kernel modules are currently loaded in memory.' },
  { id: 'lpic2-201-11', topicId: 2, question: 'What is the primary difference between `initrd` and `initramfs`?', options: ['initrd is a cpio archive; initramfs is a block device image', 'initramfs is a cpio archive extracted into a tmpfs; initrd is a block device image', 'initrd is only for UEFI', 'initramfs cannot load modules'], answer: 1, explanation: '`initramfs` is a modern, simpler approach using a compressed cpio archive loaded into a tmpfs, avoiding block device drivers early in boot.' },
  { id: 'lpic2-201-12', topicId: 2, question: 'Which command displays information about a kernel module, such as its author, description, and accepted parameters?', options: ['lsmod', 'modprobe -d', 'modinfo', 'insmod -i'], answer: 2, explanation: '`modinfo` extracts and prints information from the module object file itself.' },
  { id: 'lpic2-201-13', topicId: 2, question: 'Which command reads `sysctl.conf` and applies the kernel parameters immediately?', options: ['sysctl -w', 'sysctl -a', 'sysctl -p', 'sysctl -r'], answer: 2, explanation: '`sysctl -p` loads the configuration parameters from `/etc/sysctl.conf` (or the specified file) into the live kernel.' },
  { id: 'lpic2-201-14', topicId: 2, question: 'Where does `udev` look for its custom hardware event rules?', options: ['/etc/udev/rules.d/', '/lib/udev/rules.d/', 'Both A and B', '/var/run/udev/'], answer: 2, explanation: '`udev` reads default rules from `/lib/udev/rules.d/` and custom administrator rules from `/etc/udev/rules.d/`.' },
  { id: 'lpic2-201-15', topicId: 2, question: 'What command removes a kernel module from the live executing kernel if it is no longer in use?', options: ['rmmod', 'insmod -r', 'modprobe -r', 'Both A and C'], answer: 3, explanation: 'Both `rmmod` and `modprobe -r` can be used to remove modules, though `modprobe -r` also cleanly removes unused dependencies.' },

  { id: 'lpic2-202-6', topicId: 3, question: 'In systemd, which command sets the default target to Graphical (equivalent to runlevel 5)?', options: ['systemctl set-default graphical.target', 'systemctl isolate graphical.target', 'systemctl default graphical.target', 'ln -s /lib/systemd/system/graphical.target /etc/inittab'], answer: 0, explanation: '`systemctl set-default` changes the default boot target by updating the `/etc/systemd/system/default.target` symlink.' },
  { id: 'lpic2-202-7', topicId: 3, question: 'During a GRUB 2 boot, which key typically accesses the boot menu to edit kernel parameters if it is hidden?', options: ['F8', 'F12', 'Shift or Esc', 'Enter'], answer: 2, explanation: 'Holding `Shift` (for BIOS) or pressing `Esc` (for UEFI) interrupts the GRUB 2 boot and reveals the menu.' },
  { id: 'lpic2-202-8', topicId: 3, question: 'What does the `systemctl isolate` command do?', options: ['Restarts the system', 'Changes the current operating state to a new target, stopping unnecessary services', 'Disables network interfaces', 'Chroots into another environment'], answer: 1, explanation: '`isolate` immediately switches the system to a new target (like switching runlevels in SysV).', },
  { id: 'lpic2-202-9', topicId: 3, question: 'Which file contains the global settings (like timeout and default entry) used by grub-mkconfig to generate the GRUB 2 configuration?', options: ['/etc/grub.d/00_header', '/boot/grub/grub.cfg', '/etc/default/grub', '/boot/grub/menu.lst'], answer: 2, explanation: '`/etc/default/grub` contains variables like `GRUB_TIMEOUT` and `GRUB_CMDLINE_LINUX` that dictate generation.' },
  { id: 'lpic2-202-10', topicId: 3, question: 'What is PXE?', options: ['A partition table format', 'A method to boot an OS over the network using DHCP and TFTP', 'A Linux bootloader for ARM', 'A systemd unit type'], answer: 1, explanation: 'Preboot eXecution Environment (PXE) allows network cards to retrieve a bootloader and kernel from a network server.' },
  { id: 'lpic2-202-11', topicId: 3, question: 'Which script directory contains the modular scripts executed by `grub-mkconfig`?', options: ['/etc/default/grub', '/etc/grub.d/', '/boot/grub/scripts/', '/lib/grub/'], answer: 1, explanation: 'The `/etc/grub.d/` directory contains executable scripts (like 10_linux) that probe the system when generating grub.cfg.' },
  { id: 'lpic2-202-12', topicId: 3, question: 'What is `systemd-boot`?', options: ['A SysVinit wrapper', 'A lightweight UEFI boot manager', 'A GRUB plugin', 'A Plymouth theme'], answer: 1, explanation: '`systemd-boot` (formerly gummiboot) is a simple UEFI boot manager incorporated into systemd.' },
  { id: 'lpic2-202-13', topicId: 3, question: 'If you lose your root password, what kernel parameter can you pass in GRUB to bypass authentication?', options: ['root=/dev/null', 'init=/bin/bash', 'skip_auth=1', 'runlevel=0'], answer: 1, explanation: 'Adding `init=/bin/bash` (or /bin/sh) mounts root and drops immediately into a root shell without asking for a password.' },
  { id: 'lpic2-202-14', topicId: 3, question: 'Which command generates an initial ramdisk (initramfs) on Red Hat / CentOS systems?', options: ['mkinitcpio', 'mkinitrd / dracut', 'update-initramfs', 'initramfs-build'], answer: 1, explanation: 'RHEL-based systems historically used `mkinitrd` and now natively use `dracut` to build the initramfs.' },
  { id: 'lpic2-202-15', topicId: 3, question: 'In SysVinit, what script is typically responsible for executing the rc scripts for the defined runlevel?', options: ['/etc/rc.local', '/etc/init.d/rc', '/sbin/runlevel', '/bin/sh'], answer: 1, explanation: 'The `/etc/init.d/rc` script is invoked by init with the runlevel as an argument to start/stop the appropriate services in `/etc/rcX.d/`.' },

  { id: 'lpic2-203-6', topicId: 4, question: 'Which command displays the hardware geometry and partitions of a disk?', options: ['df -h', 'lsblk', 'fdisk -l', 'Both B and C'], answer: 3, explanation: 'Both `lsblk` and `fdisk -l` describe block devices and partitions (fdisk shows geometry details).' },
  { id: 'lpic2-203-7', topicId: 4, question: 'Which command converts an ext3 filesystem to ext4 without data loss?', options: ['tune2fs -O extents,uninit_bg,dir_index /dev/sda1', 'mkfs.ext4 /dev/sda1', 'fsck.ext4 -y /dev/sda1', 'parted /dev/sda1 convert ext4'], answer: 0, explanation: '`tune2fs` allows toggling filesystem features on an existing disk; adding ext4 features converts it.' },
  { id: 'lpic2-203-8', topicId: 4, question: 'What tool modifies the UUID of an ext2/ext3/ext4 filesystem?', options: ['uuidgen', 'blkid', 'tune2fs -U', 'xfs_admin'], answer: 2, explanation: '`tune2fs -U [UUID|random] /dev/sdX` changes the filesystem UUID on ext filesystems.' },
  { id: 'lpic2-203-9', topicId: 4, question: 'Which option in `/etc/fstab` mounts the filesystem as read-only?', options: ['rw', 'ro', 'noexec', 'nosuid'], answer: 1, explanation: 'The `ro` option specifies Read-Only mounting.' },
  { id: 'lpic2-203-10', topicId: 4, question: 'Which command provides information about the state and fragmentation of an XFS filesystem?', options: ['xfs_repair', 'xfs_info', 'xfs_db', 'None of the above'], answer: 1, explanation: '`xfs_info` prints the geometry and layout details of a mounted XFS filesystem.' },
  { id: 'lpic2-203-11', topicId: 4, question: 'How can you securely wipe a hard drive (/dev/sdb) by overwriting it with random data?', options: ['dd if=/dev/urandom of=/dev/sdb bs=1M', 'rm -rf /dev/sdb', 'mkfs.ext4 /dev/sdb', 'fdisk -w /dev/sdb'], answer: 0, explanation: '`dd` reading from `/dev/urandom` physically overwrites the target disk with unpredictable binary data.' },
  { id: 'lpic2-203-12', topicId: 4, question: 'What does the command `badblocks` do?', options: ['Formats the disk', 'Scans a device for physically damaged sectors', 'Repairs the filesystem registry', 'Identifies bad RAM'], answer: 1, explanation: '`badblocks` performs read/write tests on sectors to identify physically unusable blocks on a storage device.' },
  { id: 'lpic2-203-13', topicId: 4, question: 'Which Btrfs command takes a read-write snapshot of a subvolume?', options: ['btrfs subvolume snapshot', 'btrfs snap create', 'lvcreate -s', 'btrfs-image'], answer: 0, explanation: '`btrfs subvolume snapshot <source> <dest>` creates a Copy-on-Write snapshot.' },
  { id: 'lpic2-203-14', topicId: 4, question: 'What is `autofs`?', options: ['A tool for formatting disks', 'A daemon that automatically mounts filesystems on demand', 'A replacement for GRUB', 'A network packet router'], answer: 1, explanation: '`autofs` provides automounting (mounting only when a user accesses a specific directory) and auto-unmounting.' },
  { id: 'lpic2-203-15', topicId: 4, question: 'Which optical media authoring command creates an ISO9660 filesystem image?', options: ['cdrecord', 'mkisofs', 'growisofs', 'wodim'], answer: 1, explanation: '`mkisofs` (or genisoimage) takes a directory tree and generates an ISO9660 layout file suitable for burning.' },

  { id: 'lpic2-204-6', topicId: 5, question: 'In LVM, how do you reduce the size of a logical volume safely?', options: ['lvresize -L -10G /dev/vg/lv', 'First resize the filesystem inside the LV, then resize the LV', 'First resize the LV, then resize the filesystem', 'You cannot reduce an LV'], answer: 1, explanation: 'You must shrink the filesystem (e.g., resize2fs) BEFORE shrinking the LV to avoid corrupting data boundaries.' },
  { id: 'lpic2-204-7', topicId: 5, question: 'When managing a software RAID 5 array with `mdadm`, what happens if a drive fails?', options: ['Data is permanently lost', 'The array operates in degraded mode using parity to calculate missing data', 'The system immediately kernel panics', 'The array switches to RAID 0'], answer: 1, explanation: 'RAID 5 can tolerate exactly one drive failure, operating in "degraded mode" until rebuilt.' },
  { id: 'lpic2-204-8', topicId: 5, question: 'Which command initiates an iSCSI session to discover targets on a server?', options: ['iscsiadm -m discovery -t sendtargets -p <IP>', 'iscsid --scan', 'mount -t iscsi', 'lvscan'], answer: 0, explanation: '`iscsiadm` is the CLI tool for interacting with the open-iscsi initiator to discover and login to targets.' },
  { id: 'lpic2-204-9', topicId: 5, question: 'What does the LVM command `vgdisplay` show?', options: ['Only physical volumes', 'Only logical volumes', 'Attributes of Volume Groups such as total size, free PE, and allocated PE', 'File system UUIDs'], answer: 2, explanation: '`vgdisplay` dumps metadata regarding Volume Groups including Physical Extent (PE) capacity details.' },
  { id: 'lpic2-204-10', topicId: 5, question: 'How can you add a spare drive to an existing `mdadm` RAID array (/dev/md0)?', options: ['mdadm --add /dev/md0 /dev/sdX', 'mdadm --grow /dev/md0 --size=spare', 'mdadm --create /dev/md0 /dev/sdX', 'You cannot add spares to active arrays'], answer: 0, explanation: 'The `--add` (or `-a`) flag hot-adds a spare device to an existing array.' },
  { id: 'lpic2-204-11', topicId: 5, question: 'What is the purpose of LVM snapshots?', options: ['To create permanent backups on tape', 'To instantly capture the state of a Logical Volume (Copy-on-Write) for consistent backups', 'To speed up disk reads', 'To convert ext4 to xfs'], answer: 1, explanation: 'Snapshots track changes via CoW, allowing you to back up a frozen point-in-time state of a volume without downtime.' },
  { id: 'lpic2-204-12', topicId: 5, question: 'In an iSCSI environment, what is an IQN?', options: ['Internal Query Network', 'iSCSI Qualified Name', 'Internet Quota Node', 'Initial Queue Number'], answer: 1, explanation: 'The iSCSI Qualified Name (IQN) is a globally unique identifier for iSCSI initiators and targets.' },
  { id: 'lpic2-204-13', topicId: 5, question: 'Which `hdparm` flag gets/sets the spindown time for a drive?', options: ['-S', '-y', '-Z', '-B'], answer: 0, explanation: '`hdparm -S` sets the standby (spindown) timeout for an IDE/SATA/SAS drive.' },
  { id: 'lpic2-204-14', topicId: 5, question: 'Which file stores the status and details of `mdadm` software RAID arrays dynamically?', options: ['/etc/mdadm.conf', '/proc/mdstat', '/var/log/raid.log', '/sys/block/raid'], answer: 1, explanation: '`/proc/mdstat` provides a real-time summary of kernel software RAID arrays and their sync status.' },
  { id: 'lpic2-204-15', topicId: 5, question: 'Which LVM component is directly created on a raw disk partition?', options: ['Logical Volume (LV)', 'Volume Group (VG)', 'Physical Volume (PV)', 'Volume Extent (VE)'], answer: 2, explanation: 'A Physical Volume (PV) is the base LVM structure created directly on a disk or partition.' },

  // --- NEW BATCH 2 (Topics 205-208) ---
  { id: 'lpic2-205-6', topicId: 6, question: 'Which `ip` command assigns the IPv4 address 192.168.1.10/24 to the eth0 interface?', options: ['ip address add 192.168.1.10/24 dev eth0', 'ip addr set eth0 192.168.1.10/24', 'ip assign eth0 192.168.1.10/24', 'ifconfig eth0 add 192.168.1.10/24'], answer: 0, explanation: '`ip address add <address> dev <interface>` is the correct syntax.' },
  { id: 'lpic2-205-7', topicId: 6, question: 'What is the purpose of the `/etc/iproute2/rt_tables` file?', options: ['It stores the system ARP cache', 'It maps routing table IDs to human-readable names', 'It configures the firewall rules for iproute2', 'It assigns static IP addresses'], answer: 1, explanation: 'This file allows administrators to use symbolic names instead of numeric identifiers for policy routing tables.' },
  { id: 'lpic2-205-8', topicId: 6, question: 'Which tool is primarily used to configure parameters (like SSID or frequency) of a wireless network interface in Linux?', options: ['ifconfig', 'iwconfig', 'wpa_supplicant', 'nmcli'], answer: 1, explanation: '`iwconfig` is a CLI tool dedicated to configuring wireless extensions and wireless network interfaces.' },
  { id: 'lpic2-205-9', topicId: 6, question: 'When testing a connection, how do you instruct `ping` to specifically source its packets from the `eth1` interface?', options: ['ping -S eth1', 'ping -I eth1', 'ping -e eth1', 'ping -i eth1'], answer: 1, explanation: 'The `-I` flag explicitly binds the ping socket to a specific interface or source IP address.' },
  { id: 'lpic2-205-10', topicId: 6, question: 'Which command sets a default gateway of 10.0.0.1 using the iproute2 suite?', options: ['ip route add default via 10.0.0.1', 'route add default gw 10.0.0.1', 'ip route default 10.0.0.1', 'ip gw set 10.0.0.1'], answer: 0, explanation: '`ip route add default via <IP>` pushes a default gateway routing rule.' },
  { id: 'lpic2-205-11', topicId: 6, question: 'How can you capture network packets with 	cpdump and save them to a file named capture.pcap for later analysis in Wireshark?', options: ['tcpdump > capture.pcap', 'tcpdump -f capture.pcap', 'tcpdump -w capture.pcap', 'tcpdump -o capture.pcap'], answer: 2, explanation: 'The -w flag directs tcpdump to write the raw packets into a specified PCAP file.' },
  { id: 'lpic2-205-12', topicId: 6, question: 'Which Linux tool is often referred to as the "Swiss Army knife" of networking and can be used for port scanning, transferring files, and banner grabbing?', options: ['nmap', 'nc (netcat)', 'telnet', 'curl'], answer: 1, explanation: 'Netcat (`nc`) is a versatile utility used to read from and write to network connections using TCP or UDP.' },
  { id: 'lpic2-205-13', topicId: 6, question: 'What is the IPv6 loopback address equivalent to 127.0.0.1?', options: ['::1', 'fe80::1', '0:0:0:0:0:0:0:1', 'Both A and C'], answer: 3, explanation: '`::1` is the abbreviated format for `0:0:0:0:0:0:0:1`, which is the IPv6 localhost address.' },
  { id: 'lpic2-205-14', topicId: 6, question: 'Which switch with the `ss` utility displays all listening *and* established (non-listening) sockets?', options: ['ss -l', 'ss -a', 'ss -t', 'ss -u'], answer: 1, explanation: '`ss -a` (all) prints both listening and non-listening sockets together.' },
  { id: 'lpic2-205-15', topicId: 6, question: 'By default, what type of packet does the traditional Linux `traceroute` command send to probe the path?', options: ['TCP SYN', 'ICMP Echo Request', 'UDP datagrams', 'IGMP queries'], answer: 2, explanation: 'Unlike Windows `tracert` which uses ICMP, standard Linux `traceroute` leverages UDP datagrams targeting incrementally increasing high port numbers.' },

  { id: 'lpic2-206-6', topicId: 7, question: 'Which utility can replace `make install` to create a Slackware, RPM, or Debian package from the compiled source for easier removal later?', options: ['autotools', 'checkinstall', 'dpkg-buildpackage', 'rpmbuild'], answer: 1, explanation: '`checkinstall` tracks the files installed by `make install` and creates a package (like .deb or .rpm) for clean package management.' },
  { id: 'lpic2-206-7', topicId: 7, question: 'Which tool traces the dynamic library calls made by an executable (as opposed to system calls)?', options: ['strace', 'ltrace', 'ldd', 'objdump'], answer: 1, explanation: '`ltrace` intercepts and records the dynamic library calls bound to an executable during execution.' },
  { id: 'lpic2-206-8', topicId: 7, question: 'When extracting a tarball that was compressed using `bzip2`, which typical flag is passed to `tar`?', options: ['-z', '-J', '-j', '-b'], answer: 2, explanation: 'The `-j` flag tells GNU tar to decompress using bzip2.' },
  { id: 'lpic2-206-9', topicId: 7, question: 'Which command controls magnetic tape drive operations such as rewinding and ejecting?', options: ['tape', 'mt', 'tar', 'cpio'], answer: 1, explanation: '`mt` (magnetic tape) is the standard utility invoked to control tape drive physical mechanisms.' },
  { id: 'lpic2-206-10', topicId: 7, question: 'In `rsync`, what does the `-a` (archive) flag do?', options: ['It compresses the data', 'It syncs recursively and preserves permissions, times, ownership, and symlinks', 'It deletes extraneous files from destination', 'It only copies hidden files'], answer: 1, explanation: 'Archive mode (`-a`) equals `-rlptgoD`, making it the perfect flag for performing identical directory syncing.' },
  { id: 'lpic2-206-11', topicId: 7, question: 'Which systemd command signals a daemon to simply re-read its configuration files without dropping active connections?', options: ['systemctl restart', 'systemctl reload', 'systemctl force-reload', 'systemctl refresh'], answer: 1, explanation: '`reload` safely instructs a service to re-parse its configs without a hard interruption.' },
  { id: 'lpic2-206-12', topicId: 7, question: 'What is the standard directory structure on a Linux file system specifically designated to hold most generic service logs?', options: ['/usr/log/', '/var/spool/log/', '/var/log/', '/etc/logs/'], answer: 2, explanation: 'The `/var/log/` directory is the FHS-compliant standard for system and application log outputs.' },
  { id: 'lpic2-206-13', topicId: 7, question: 'How can you attach `strace` to a daemon process that is already running?', options: ['strace -a <PID>', 'strace -p <PID>', 'strace --attach <PID>', 'strace <PID>'], answer: 1, explanation: 'The `-p` flag forces strace to hook into the specified Process ID dynamically.' },
  { id: 'lpic2-206-14', topicId: 7, question: 'When creating an exact bit-wise backup of a disk partition with `dd`, which parameter defines the size of chunks read/written to drastically improve speed?', options: ['count=', 'bs=', 'size=', 'chunk='], answer: 1, explanation: '`bs` (block size) dictates the amount of bytes read and written at a time, for example: `bs=4M`.' },
  { id: 'lpic2-206-15', topicId: 7, question: 'Which command generates an OpenSSH authentication key pair?', options: ['ssh-agent', 'ssh-add', 'ssh-keygen', 'ssh-copy-id'], answer: 2, explanation: '`ssh-keygen` mathematically generates public/private key pairs for SSH protocol authentication.' },

  { id: 'lpic2-207-6', topicId: 8, question: 'In a BIND zone config, what does the SOA record represent?', options: ['Secure Origin Auth', 'Start of Authority', 'Server Origin Address', 'System Oriented Architecture'], answer: 1, explanation: 'The Start of Authority (SOA) record is mandatory in a zone file and defines global parameters for the zone, like the TTL and primary nameserver.' },
  { id: 'lpic2-207-7', topicId: 8, question: 'What is a BIND `CNAME` record primarily used for?', options: ['To delegate a subdomain to another zone', 'To assign a mail server', 'To map an alias name to a true, canonical A or AAAA name', 'To encrypt traffic'], answer: 2, explanation: 'Canonical Name (CNAME) acts as an alias tying one domain directly to another.' },
  { id: 'lpic2-207-8', topicId: 8, question: 'Which tool can you use to query a DNS server interactively or from the CLI to debug specific records (like MX or TXT)?', options: ['named', 'dig', 'ping', 'ipconfig'], answer: 1, explanation: '`dig` (Domain Information Groper) is the preferred standard utility for deep DNS querying and troubleshooting.' },
  { id: 'lpic2-207-9', topicId: 8, question: 'In BIND, what is the special reserved suffix used when defining an IPv4 Reverse Lookup Zone that maps IP addresses back to hostnames?', options: ['.local', '.in-addr.arpa', '.ip.reverse', '.arpa.net'], answer: 1, explanation: 'Reverse IPv4 mappings are standardized under the special `.in-addr.arpa` domain hierarchy.' },
  { id: 'lpic2-207-10', topicId: 8, question: 'What is the role of the `/etc/resolv.conf` file?', options: ['It configures BIND server zones', 'It dictates which DNS servers the local machine should query to resolve hostnames', 'It configures the firewall', 'It blocks malcious IP addresses'], answer: 1, explanation: 'The resolver configuration file tells the local system network stack which DNS IP addresses to ask.' },
  { id: 'lpic2-207-11', topicId: 8, question: 'Which BIND command flushes the DNS cache and cleanly reloads zones without restarting the `named` daemon?', options: ['systemctl restart bind', 'rndc reload', 'named -reload', 'bind-flush'], answer: 1, explanation: '`rndc` is the BIND remote name daemon control utility; `rndc reload` cleanly rereads the config and zones.' },
  { id: 'lpic2-207-12', topicId: 8, question: 'In DNSSEC, what is a DS record?', options: ['Domain Signature', 'Delegation Signer', 'Digital Security', 'Data Synchronizer'], answer: 1, explanation: 'The Delegation Signer (DS) record is published in the parent zone to establish a chain of trust to a child zone.' },
  { id: 'lpic2-207-13', topicId: 8, question: 'Which mechanism is most commonly utilized in BIND to cryptographically secure and authorize zone transfers (AXFR) between master and slave DNS servers?', options: ['DNSSEC', 'TSIG', 'TLS', 'IPsec'], answer: 1, explanation: 'Transaction Signature (TSIG) uses shared secret keys to securely authenticate communication between DNS servers.' },
  { id: 'lpic2-207-14', topicId: 8, question: 'In a BIND SOA record, what is the purpose of the "Serial Number"?', options: ['It specifies the number of domains in the zone', 'It uniquely identifies the server hardware', 'It tells slave servers whether their cached zone file is outdated and needs a resync', 'It acts as the encryption key'], answer: 2, explanation: 'Secondary servers check the serial number; if the primary\'s serial is higher, a zone transfer is initiated.' },
  { id: 'lpic2-207-15', topicId: 8, question: 'When securing BIND, it is common best practice to run the `named` process in a heavily restricted environment. What is this security technique called?', options: ['Containerization', 'Chroot Jail', 'VPN encapsulation', 'SELinux Disabled'], answer: 1, explanation: 'Chrooting limits the BIND process to a specific sub-directory, preventing it from accessing the root system if compromised.' },

  { id: 'lpic2-208-6', topicId: 9, question: 'In an Apache configuration, which directive specifies the main directory out of which files are served for a domain?', options: ['ServerRoot', 'DocumentRoot', 'DirectoryIndex', 'WebRoot'], answer: 1, explanation: '`DocumentRoot` points to the physical directory path where the HTML files reside.' },
  { id: 'lpic2-208-7', topicId: 9, question: 'Which Nginx directive is critical to implementing a reverse proxy to a backend application server?', options: ['fastcgi_pass', 'server_name', 'proxy_pass', 'location_root'], answer: 2, explanation: '`proxy_pass` explicitly forwards HTTP requests to a proxied backend server (like a Node.js or Tomcat instance).' },
  { id: 'lpic2-208-8', topicId: 9, question: 'What does the Apache module `mod_rewrite` accomplish?', options: ['It translates languages on the fly', 'It compresses HTML data', 'It dynamically parses and rewrites URL requests based on regular expression rules', 'It prevents SQL injection'], answer: 2, explanation: '`mod_rewrite` is an advanced URL manipulation engine routing URLs to specific controllers.' },
  { id: 'lpic2-208-9', topicId: 9, question: 'What is an `.htaccess` file used for in Apache?', options: ['To store encrypted passwords', 'To define global server limits', 'To allow decentralized, directory-level configuration overrides without editing the main server config', 'To block ping requests'], answer: 2, explanation: 'It is a decentralized configuration file allowing developers to apply rules (like rewrites) directly within a directory.' },
  { id: 'lpic2-208-10', topicId: 9, question: 'In Squid, you write: `acl LAN src 192.168.1.0/24`. What must you do to actually enforce traffic drops to this LAN?', options: ['http_access allow LAN', 'http_access deny LAN', 'squid_deny LAN', 'acl deny LAN'], answer: 1, explanation: 'An ACL only defines a group. An `http_access` rule is then required to explicitly `allow` or `deny` that ACL.' },
  { id: 'lpic2-208-11', topicId: 9, question: 'From an architectural standpoint, why does Nginx historically handle vast amounts of concurrent connections more efficiently than the standard Apache Prefork MPM?', options: ['Nginx executes faster C code', 'Nginx utilizes an asynchronous, event-driven non-blocking architecture', 'Apache lacks cache mechanisms', 'Nginx uses UDP'], answer: 1, explanation: 'Nginx\'s event loop easily juggles thousands of connections within a single thread, avoiding process-spawning overhead.' },
  { id: 'lpic2-208-12', topicId: 9, question: 'In Squid, what is a "parent" cache peer?', options: ['A backend database server', 'Another proxy server that Squid forwards cache-miss traffic to, asking it to fetch the object', 'The default Gateway IP', 'A Load balancer'], answer: 1, explanation: 'A parent cache resolves internet requests on behalf of the child Squid server in a proxy hierarchy.' },
  { id: 'lpic2-208-13', topicId: 9, question: 'Which Nginx core configuration directive usually matches the number of CPU cores to maximize performance?', options: ['max_connections', 'worker_processes', 'server_workers', 'events'], answer: 1, explanation: '`worker_processes auto;` or setting it to the CPU core count allows Nginx to fully utilize the processor hardware.' },
  { id: 'lpic2-208-14', topicId: 9, question: 'Which Apache directive in a `<VirtualHost>` block specifies the domain names the Host will respond to?', options: ['DNSName', 'Hostname', 'ServerName and ServerAlias', 'Domain'], answer: 2, explanation: '`ServerName` assigns the primary domain, and `ServerAlias` specifies alternative hostnames.' },
  { id: 'lpic2-208-15', topicId: 9, question: 'What does the `squid -k reconfigure` command do?', options: ['Kills the squid process abruptly', 'Clears the cache entirely', 'Sends a signal to a running Squid process to reload the squid.conf file without disconnecting clients', 'Downloads updates'], answer: 2, explanation: 'Similar to an Nginx or systemctl reload, `-k reconfigure` is the safe way to apply Squid configuration changes.' },
  { id: 'lpic2-209-6', topicId: 10, question: 'Which command displays the current active connections and locked files on a Samba server?', options: ['smbstatus', 'testparm', 'smbclient', 'netstat -smb'], answer: 0, explanation: '`smbstatus` reports on current Samba connections, including the users, machines, and locked files.' },
  { id: 'lpic2-209-7', topicId: 10, question: 'Before restarting Samba, which utility should you use to check `smb.conf` for internal correctness and syntax errors?', options: ['smb-check', 'testparm', 'smbclient -t', 'smbpasswd -check'], answer: 1, explanation: '`testparm` reads `smb.conf` and checks it for configuration parsing errors.' },
  { id: 'lpic2-209-8', topicId: 10, question: 'Which command allows a Linux desktop user to interactively browse and transfer files from a Windows network share similarly to FTP?', options: ['mount.cifs', 'winbound', 'smbclient', 'samba-ftpd'], answer: 2, explanation: '`smbclient` is an FTP-like client to access SMB/CIFS resources on servers.' },
  { id: 'lpic2-209-9', topicId: 10, question: 'What major architectural difference distinguishes NFSv4 from NFSv3?', options: ['NFSv4 uses UDP only', 'NFSv4 integrates file locking and mounting into a single protocol over TCP port 2049, removing the need for rpcbind', 'NFSv4 cannot be mounted over the Internet', 'NFSv3 is faster for wide-area networks'], answer: 1, explanation: 'NFSv4 is firewall-friendly because it consolidates mounting, locking, and file transfer into a single port (TCP 2049).' },
  { id: 'lpic2-209-10', topicId: 10, question: 'Which command queries a remote NFS server (at 192.168.1.50) to see what directories it is currently exporting?', options: ['showmount -e 192.168.1.50', 'exportfs -v 192.168.1.50', 'nfsstat -m 192.168.1.50', 'mount -l 192.168.1.50'], answer: 0, explanation: '`showmount -e` displays the export list of an NFS server.' },
  { id: 'lpic2-209-11', topicId: 10, question: 'What does the `nfsstat` command provide?', options: ['It restarts the NFS daemon', 'It displays statistics regarding NFS client and server activity to help diagnose performance issues', 'It formats a disk for NFS', 'It tests network speeds between nodes'], answer: 1, explanation: '`nfsstat` outputs detailed Remote Procedure Call (RPC) and NetworkFileSystem statistical metrics.' },
  { id: 'lpic2-209-12', topicId: 10, question: 'In advanced Samba configurations, what daemon maps Windows SID identifiers to assigned Linux UIDs/GIDs in an Active Directory environment?', options: ['smbd', 'nmbd', 'winbindd', 'kerberosd'], answer: 2, explanation: '`winbindd` resolves names from NT servers and provides a unified ID mapping facility for domain users.' },
  { id: 'lpic2-209-13', topicId: 10, question: 'Legacy NFS (v3) relies heavily on a daemon that maps RPC program numbers to network port numbers. What is this daemon called?', options: ['rpcbind (or portmap)', 'inetd', 'xinetd', 'rpc.nfsd'], answer: 0, explanation: '`rpcbind` (formerly `portmap`) dynamically assigns varying ports for older NFS auxiliary services like rpc.statd.' },
  { id: 'lpic2-209-14', topicId: 10, question: 'Which global parameter in `smb.conf` dictates the name of the Windows domain or workgroup the Samba server will appear in?', options: ['domain =', 'netbios name =', 'server string =', 'workgroup ='], answer: 3, explanation: 'The `workgroup` parameter sets the workgroup/domain name.' },
  { id: 'lpic2-209-15', topicId: 10, question: 'Which command mounts a Windows share natively into the Linux file system tree?', options: ['mount -t ntfs //server/share /mnt', 'mount -t smbfs //server/share /mnt', 'mount -t cifs -o username=user //server/share /mnt', 'smbclient //server/share /mnt'], answer: 2, explanation: 'Modern Linux uses the kernel `cifs` Virtual File System module to mount SMB shares.' },
  { id: 'lpic2-209-16', topicId: 10, question: 'When reviewing `/etc/exports`, what does the `no_root_squash` parameter do?', options: ['It prevents root access entirely', 'It allows the remote root user to maintain root privileges on the exported directory', 'It compresses files accessed by root', 'It maps root to the nobody user'], answer: 1, explanation: 'Normally, NFS squashes root requests to an anonymous UID. `no_root_squash` overrides this, presenting a severe security risk if used carelessly.' },

  { id: 'lpic2-210-6', topicId: 11, question: 'In the ISC DHCP server configuration (`dhcpd.conf`), which parameter defines the default duration an IP is leased to a client if they do not request a specific timeframe?', options: ['max-lease-time', 'default-lease-time', 'lease-duration', 'expire-time'], answer: 1, explanation: '`default-lease-time` is the standard allocation time in seconds.' },
  { id: 'lpic2-210-7', topicId: 11, question: 'Which ISC DHCP daemon creates the centralized log of leased IPs, effectively storing state across reboots?', options: ['/etc/dhcp/dhcpd.conf', '/var/lib/dhclient/dhclient.leases', '/var/lib/dhcp/dhcpd.leases', '/var/log/dhcpd.log'], answer: 2, explanation: 'The `dhcpd.leases` file serves as the database for tracking active allocations.' },
  { id: 'lpic2-210-8', topicId: 11, question: 'What are the four management groups within a PAM module configuration file?', options: ['allow, deny, warn, critical', 'auth, account, password, session', 'user, group, other, root', 'login, shell, network, local'], answer: 1, explanation: 'PAM organizes rules into auth (identity), account (validity), password (updating credentials), and session (setup/teardown).' },
  { id: 'lpic2-210-9', topicId: 11, question: 'In a PAM stack, what happens if a module marked as `requisite` fails?', options: ['The stack immediately returns failure without executing further modules', 'The failure is recorded, but the next module is tested', 'It drops the user to a limited shell', 'It prompts the user for a CAPTCHA'], answer: 0, explanation: 'Unlike `required`, `requisite` causes instant failure avoiding further processing.' },
  { id: 'lpic2-210-10', topicId: 11, question: 'By default, what TCP port does unencrypted LDAP operate on?', options: ['110', '389', '636', '3306'], answer: 1, explanation: 'LDAP communicates over TCP port 389, while LDAPS (LDAP over SSL) uses port 636.' },
  { id: 'lpic2-210-11', topicId: 11, question: 'Which daemon is the core engine of the OpenLDAP server suite?', options: ['ldap_agent', 'named', 'slapd', 'sssd'], answer: 2, explanation: '`slapd` stands for Stand-Alone LDAP Daemon.' },
  { id: 'lpic2-210-12', topicId: 11, question: 'Which command-line utility queries an LDAP directory using filters?', options: ['ldapquery', 'ldapsearch', 'ldaplookup', 'ldapfind'], answer: 1, explanation: '`ldapsearch` opens a connection to an LDAP server, binds, and performs a search using a given filter.' },
  { id: 'lpic2-210-13', topicId: 11, question: 'What modern daemon is used heavily in Linux to cache credentials and manage connections to central directories like LDAP or Active Directory?', options: ['nscd', 'sssd', 'pam_unix', 'winbind'], answer: 1, explanation: 'System Security Services Daemon (SSSD) integrates the system with remote central directories and provides offline caching.' },
  { id: 'lpic2-210-14', topicId: 11, question: 'In OpenVPN, routing all client internet traffic through the VPN requires pushing which specific directive to the client?', options: ['push "route 0.0.0.0 0.0.0.0"', 'push "redirect-gateway def1"', 'push "default-route"', 'route-all'], answer: 1, explanation: '`redirect-gateway def1` modifies the client\'s default routing table to point to the VPN tunnel.' },
  { id: 'lpic2-210-15', topicId: 11, question: 'What command forces a Linux client to manually release its DHCP leased IP address and halt the daemon?', options: ['dhclient -x', 'dhclient -r', 'ifdown eth0', 'ip addr flush'], answer: 1, explanation: '`dhclient -r` explicitly releases the current lease to the server and stops the client daemon.' },
  { id: 'lpic2-210-16', topicId: 11, question: 'What is the standard suffix/extension for the certificate authority file used to authenticate OpenVPN clients?', options: ['.key', '.crt', '.csr', '.ca'], answer: 1, explanation: 'Certificates (public keys) generally use the `.crt` or `.pem` extension.' },

  { id: 'lpic2-211-6', topicId: 12, question: 'Which command displays the current contents of the Postfix mail queue?', options: ['mailq', 'postqueue -p', 'Both A and B', 'qstat'], answer: 2, explanation: '`mailq` is usually a symlink to `postqueue -p`, which prints the queue.' },
  { id: 'lpic2-211-7', topicId: 12, question: 'What does the Postfix command `postsuper -d ALL` do?', options: ['Deletes all mail from the mail queue', 'Downloads all mail from the MTA', 'Deploys a new supervisor config', 'Disables the mail server'], answer: 0, explanation: '`postsuper` manages the Postfix queue; `-d ALL` irretrievably deletes every message in the queue.' },
  { id: 'lpic2-211-8', topicId: 12, question: 'Which parameter in `main.cf` defines what domain names Postfix considers itself the final destination for?', options: ['myhostname', 'mynetworks', 'mydestination', 'relay_domains'], answer: 2, explanation: 'Mails addressed to domains listed in `mydestination` are delivered locally.' },
  { id: 'lpic2-211-9', topicId: 12, question: 'If you want Postfix to reject emails from known spammer IP addresses globally, which directive would you configure to use DNS Blocklists (DNSBL)?', options: ['smtpd_recipient_restrictions', 'smtpd_client_restrictions', 'header_checks', 'virtual_alias_maps'], answer: 1, explanation: '`smtpd_client_restrictions = reject_rbl_client zen.spamhaus.org` evaluates the connecting IP before any transaction.' },
  { id: 'lpic2-211-10', topicId: 12, question: 'Which port is historically reserved for the POP3 protocol (unencrypted)?', options: ['25', '110', '143', '993'], answer: 1, explanation: 'Post Office Protocol version 3 operates on TCP port 110.' },
  { id: 'lpic2-211-11', topicId: 12, question: 'In Dovecot, what is the default port for IMAPS (Secure IMAP over SSL/TLS)?', options: ['143', '465', '587', '993'], answer: 3, explanation: 'IMAPs leverages implicitly secure TLS over TCP port 993.' },
  { id: 'lpic2-211-12', topicId: 12, question: 'Which MDA script language is considered the modern, standardized alternative to Procmail, designed specifically to integrate cleanly with Dovecot?', options: ['Bash', 'Python', 'Sieve', 'Perl'], answer: 2, explanation: 'Sieve is a highly secure, standardized scripting language for filtering emails at the MTA/MDA level.' },
  { id: 'lpic2-211-13', topicId: 12, question: 'Where are Procmail recipes typically defined on a per-user basis?', options: ['/etc/procmail.conf', '~/.procmailrc', '/var/spool/mail/recipes', '~/.mailfilter'], answer: 1, explanation: 'Users create personal mail routing recipes in `.procmailrc` in their home directories.' },
  { id: 'lpic2-211-14', topicId: 12, question: 'What is the function of the `mynetworks` parameter in Postfix?', options: ['It blocks spam from those networks', 'It defines the list of local networks permitted to relay mail through the server to outside domains', 'It maps local IP addresses', 'It defines the IP interfaces Postfix listens on'], answer: 1, explanation: 'Clients coming from IPs matched in `mynetworks` are implicitly trusted to relay mail.' },
  { id: 'lpic2-211-15', topicId: 12, question: 'Which command forces Postfix to immediately attempt delivery of all deferred messages sitting in the queue?', options: ['postsuper -r', 'postfix flush', 'postqueue -f', 'mailq -f'], answer: 2, explanation: '`postqueue -f` iterates over the mail queue and attempts an immediate flush.' },
  { id: 'lpic2-211-16', topicId: 12, question: 'What does the Postfix `virtual_alias_maps` directive configure?', options: ['Maps virtual domains to physical IP addresses', 'Forwards emails from one specific address (e.g., info@domain.com) to real destination mailboxes', 'Maps external IP addresses to internal servers', 'Creates automated vacation replies'], answer: 1, explanation: 'Virtual aliases rewrite recipient addresses, commonly used for forwarding.' },

  { id: 'lpic2-212-6', topicId: 13, question: 'In iptables, which switch appends a rule to the very bottom of a chain?', options: ['-I', '-A', '-D', '-R'], answer: 1, explanation: '`-A` stands for Append, while `-I` inserts a rule at the top (or a specified line number).' },
  { id: 'lpic2-212-7', topicId: 13, question: 'Which command lists all iptables rules in the NAT table?', options: ['iptables -L', 'iptables -t nat -L', 'iptables -nL --table nat', 'iptables --list nat'], answer: 1, explanation: '`-t nat` specifies the table target, and `-L` lists the rules.' },
  { id: 'lpic2-212-8', topicId: 13, question: 'Which filter chain in iptables handles packets whose final destination is the server itself?', options: ['FORWARD', 'OUTPUT', 'INPUT', 'PREROUTING'], answer: 2, explanation: 'The `INPUT` chain processes incoming packets addressed to local sockets.' },
  { id: 'lpic2-212-9', topicId: 13, question: 'In `iptables`, what does the `MASQUERADE` target do?', options: ['It hides the packet data', 'It translates the source IP of outgoing packets dynamically to the IP of the outgoing interface', 'It blocks known hackers', 'It creates a VPN tunnel'], answer: 1, explanation: 'Masquerading is dynamic SNAT, heavily used on routers with dynamic public IPs.' },
  { id: 'lpic2-212-10', topicId: 13, question: 'With Nmap, what does the `-sS` flag specify?', options: ['UDP scan', 'TCP SYN (Stealth) scan', 'TCP Connect scan', 'FIN scan'], answer: 1, explanation: 'The SYN scan performs a highly efficient half-open TCP handshake to map ports.' },
  { id: 'lpic2-212-11', topicId: 13, question: 'Which command-line argument tells Nmap to attempt to identify the remote host\'s Operating System?', options: ['-O', '-sV', '-A', 'Both A and C'], answer: 3, explanation: '`-O` specifically enables OS detection. `-A` (Aggressive) enables OS detection along with version scanning and script scanning.' },
  { id: 'lpic2-212-12', topicId: 13, question: 'In Fail2ban, what file should administrators use to customize jail configurations to prevent package updates from overwriting them?', options: ['jail.conf', 'fail2ban.conf', 'jail.local', 'iptables.local'], answer: 2, explanation: '`jail.local` overrides `jail.conf`, serving as the safe repository for local modifications.' },
  { id: 'lpic2-212-13', topicId: 13, question: 'Which variable in Fail2ban defines the duration (in seconds) that an offending IP remains blocked?', options: ['blocktime', 'findtime', 'maxretry', 'bantime'], answer: 3, explanation: '`bantime` defines how long the iptables DROP injection is left in place.' },
  { id: 'lpic2-212-14', topicId: 13, question: 'What is the foundational kernel framework that iptables relies on to hook into the networking stack?', options: ['BPF', 'Netfilter', 'TCP Wrapper', 'AppArmor'], answer: 1, explanation: 'Netfilter provides the hooks in the Linux kernel that allow iptables/nftables to intercept and manipulate packets.' },
  { id: 'lpic2-212-15', topicId: 13, question: 'Which command permanently saves iptables rules to standard output across most distributions for backup scripting?', options: ['iptables-save', 'iptables-backup', 'iptables -S', 'service iptables save'], answer: 0, explanation: '`iptables-save` dumps the rules in a readable machine format (which can be restored via `iptables-restore`).' },
  { id: 'lpic2-212-16', topicId: 13, question: 'What is a Network Vulnerability Test (NVT) in the context of OpenVAS/Greenbone?', options: ['A packet sniffer', 'A plugin script providing the logic to detect a specific vulnerability on a remote host', 'A port scan technique', 'An intrusion detection rule'], answer: 1, explanation: 'NVTs are essentially the signature scripts executed by OpenVAS to confirm if a target is vulnerable.' },
  { id: 'lpic2-212-17', topicId: 13, question: 'Which command flushes (deletes) all rules in the currently selected iptables table?', options: ['iptables -X', 'iptables -Z', 'iptables -F', 'iptables -R'], answer: 2, explanation: '`-F` (Flush) instantly deletes all rules from all chains (or a specified chain).' }
];
